// ===== Error boundary for the heavy render-mode trees =====
// Cesium's internal lifecycle occasionally throws TypeErrors during
// React commits (most notably during mode-switch teardown when a Cesium
// CallbackProperty is read after the viewer is destroyed). Without an
// error boundary, React 19 unmounts the ENTIRE app tree on any
// uncaught commit-phase error — which is exactly what made
// "press S to switch modes" a one-way ticket to a blank page.
//
// This boundary catches any such error, logs it, swaps in a small
// recovery UI with a "Reload" button + the underlying error message,
// and keeps the rest of the React tree alive. resetKey lets a parent
// re-mount the boundary after a state change (e.g. mode flip) so a
// new attempt can start clean.
class RenderModeErrorBoundary extends Component<
  { children: ReactNode; resetKey?: string | number; label: string },
  { error: Error | null }
> {
  state = { error: null as Error | null };
  retryTimer: ReturnType<typeof setTimeout> | null = null;
  static getDerivedStateFromError(error: Error) {
    return { error };
  }
  componentDidCatch(error: Error, info: { componentStack?: string }) {
    // eslint-disable-next-line no-console
    console.error(`[atlas:${this.props.label}] caught render error`, error, info);
    // Most errors that hit this boundary in practice are TRANSIENT
    // — Cesium throws a TypeError during sibling unmount, the
    // Three.js scene throws a one-frame raycaster glitch, etc. The
    // recovery UI is jarring for these cases. Auto-retry after 500ms;
    // if the next render succeeds, clear the error and return to
    // normal. If it fails again, the boundary catches it again.
    // 500ms is short enough to be invisible (a single dropped frame),
    // long enough that the unmount completes first.
    if (this.retryTimer) clearTimeout(this.retryTimer);
    this.retryTimer = setTimeout(() => {
      if (this.state.error) this.setState({ error: null });
    }, 500);
  }
  componentDidUpdate(prevProps: { resetKey?: string | number }) {
    if (prevProps.resetKey !== this.props.resetKey && this.state.error) {
      this.setState({ error: null });
    }
  }
  componentWillUnmount() {
    if (this.retryTimer) clearTimeout(this.retryTimer);
  }
  render() {
    if (this.state.error) {
      return (
        <div style={{
          position: "fixed",
          inset: "44px 340px 28px 52px",
          display: "grid",
          placeItems: "center",
          background: "radial-gradient(ellipse at center, #1a1224, #04050a)",
          color: "#fff",
          fontFamily: "ui-sans-serif, system-ui",
          textAlign: "center",
          padding: 24,
          zIndex: 50,
        }}>
          <div style={{ maxWidth: 420 }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>🌍</div>
            <h2 style={{ margin: "0 0 8px", fontSize: 18 }}>
              {this.props.label === "surface" ? "Surface mode hit a snag" : "Globe view hit a snag"}
            </h2>
            <p style={{ color: "rgba(255,255,255,0.7)", fontSize: 13, margin: "0 0 16px" }}>
              {this.state.error.message?.slice(0, 200) || "Something unexpected happened during render."}
            </p>
            <button
              type="button"
              onClick={() => window.location.reload()}
              style={{
                padding: "8px 18px",
                border: 0,
                borderRadius: 99,
                background: "#5cb5ff",
                color: "#04060c",
                fontWeight: 700,
                cursor: "pointer",
                fontSize: 13,
              }}
            >
              Reload
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

// ===== Cached fetch helper for reverse-geocode + Wikipedia =====
// Many features call Nominatim and Wikipedia REST APIs with the same
// (lat, lon) repeatedly: pin auto-naming, click toasts, "what's here?"
// commands, weather lookups, etc. Caching cuts redundant network traffic
// AND speeds up the visible UI (no fetch latency on cache hit).
//
// Strategy: localStorage with TTL. Key = `${prefix}:${quantizedLat},${quantizedLon}`
// — quantized to 0.05° (~5km) so nearby coords share a cache entry. TTL
// 24h for reverse-geocode (place names rarely change), 7d for Wikipedia
// (article extracts even less so).
//
// Max 200 entries per prefix; on overflow we evict the oldest 40.
type CacheEntry<T> = { v: T; t: number };
function cacheKey(prefix: string, lat: number, lon: number, q = 20): string {
  // q=20 → quantize to 0.05° (~5.5 km at equator)
  const qlat = Math.round(lat * q) / q;
  const qlon = Math.round(lon * q) / q;
  return `atlas-cache:${prefix}:${qlat.toFixed(2)},${qlon.toFixed(2)}`;
}
function cacheGet<T>(key: string, ttlMs: number): T | null {
  try {
    const raw = window.localStorage.getItem(key);
    if (!raw) return null;
    const entry = JSON.parse(raw) as CacheEntry<T>;
    if (Date.now() - entry.t > ttlMs) {
      window.localStorage.removeItem(key);
      return null;
    }
    return entry.v;
  } catch { return null; }
}
function cacheSet<T>(key: string, value: T): void {
  try {
    const entry: CacheEntry<T> = { v: value, t: Date.now() };
    window.localStorage.setItem(key, JSON.stringify(entry));
  } catch (e) {
    // QuotaExceeded → evict 40 oldest atlas-cache entries and retry once
    if ((e as DOMException)?.name === "QuotaExceededError") {
      const allKeys = Object.keys(window.localStorage).filter(k => k.startsWith("atlas-cache:"));
      const withTimes = allKeys
        .map(k => {
          try { return { k, t: (JSON.parse(window.localStorage.getItem(k)!) as CacheEntry<unknown>).t }; }
          catch { return { k, t: 0 }; }
        })
        .sort((a, b) => a.t - b.t);
      for (let i = 0; i < Math.min(40, withTimes.length); i++) {
        try { window.localStorage.removeItem(withTimes[i].k); } catch { /* ignore */ }
      }
      try {
        const entry: CacheEntry<T> = { v: value, t: Date.now() };
        window.localStorage.setItem(key, JSON.stringify(entry));
      } catch { /* give up */ }
    }
  }
}

// Cached reverse-geocode. Returns place data from Nominatim, cached 24h
// at ~5km grid resolution. Drops in for direct nominatim fetch calls.
type ReverseGeocodeResult = { display_name?: string; address?: Record<string, string> };
async function cachedReverseGeocode(lat: number, lon: number, zoom = 10): Promise<ReverseGeocodeResult | null> {
  const key = cacheKey(`rg${zoom}`, lat, lon);
  const cached = cacheGet<ReverseGeocodeResult>(key, 24 * 60 * 60 * 1000);
  if (cached) return cached;
  try {
    const res = await fetch(
      `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&zoom=${zoom}`,
      { headers: { Accept: "application/json" } }
    );
    if (!res.ok) return null;
    const data = await res.json() as ReverseGeocodeResult;
    cacheSet(key, data);
    return data;
  } catch {
    return null;
  }
}

// Cached Wikipedia summary. Article extracts cached 7 days.
type WikiSummary = { extract?: string; content_urls?: { desktop?: { page?: string } } };
async function cachedWikiSummary(title: string): Promise<WikiSummary | null> {
  const key = `atlas-cache:wiki:${title.toLowerCase().slice(0, 80)}`;
  const cached = cacheGet<WikiSummary>(key, 7 * 24 * 60 * 60 * 1000);
  if (cached) return cached;
  try {
    const res = await fetch(
      `https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(title)}`,
      { headers: { Accept: "application/json" } }
    );
    if (!res.ok) return null;
    const data = await res.json() as WikiSummary;
    cacheSet(key, data);
    return data;
  } catch {
    return null;
  }
}
